// Anonymous workspace bootstrap — bots can mint these without an email. Cap to
// prevent disk-DoS-by-tenant-row.
const ROUTER_REPO_ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const PRODUCT_GRAPH_PATH = path.join(ROUTER_REPO_ROOT, 'public', 'product-graph.json');
// 30s TTL cache: /v1/product/graph used to re-read + JSON.parse a 100+KB file
// on every request. The graph file changes at deploy time, never within a
// request window, so 30s is comfortably safe. (WC15)
let _productGraphCache = null;
let _productGraphAt = 0;
const PRODUCT_GRAPH_TTL_MS = 30_000;
function readProductGraph() {
  const now = Date.now();
  if (_productGraphCache && (now - _productGraphAt) < PRODUCT_GRAPH_TTL_MS) {
    return _productGraphCache;
  }
  try {
    _productGraphCache = JSON.parse(fs.readFileSync(PRODUCT_GRAPH_PATH, 'utf8'));
    _productGraphAt = now;
    return _productGraphCache;
  } catch (e) {
    // Don't cache failure — let the next request retry the disk read.
    _productGraphCache = null;
    _productGraphAt = 0;
    return {
      schema: 'kolm-product-graph-1',
      ok: false,
      error: 'product_graph_unavailable',
      detail: String(e && e.message || e),
    };
  }
}
export function _resetProductGraphCacheForTests() {
  _productGraphCache = null;
  _productGraphAt = 0;
}

// R-6 — Workspace context loader. Folds the procurement vault (sig-lite +
// caiq) into a single workspace shape that buildAssuranceCase consumes.
// Best-effort: missing files leave the corresponding key undefined, which
// downgrades vault-derived claims rather than crashing the endpoint.
function _loadWorkspaceForAssuranceRoute(workspace_id = null) {
  const ws = { id: workspace_id, procurement_vault: {}, drift_namespaces: {} };
  const sigPath = path.join(ROUTER_REPO_ROOT, 'data', 'procurement', 'sig-lite.json');
  const caiqPath = path.join(ROUTER_REPO_ROOT, 'data', 'procurement', 'caiq-v4.json');
  try { if (fs.existsSync(sigPath)) ws.procurement_vault.sig_lite = JSON.parse(fs.readFileSync(sigPath, 'utf8')); } catch {} // deliberate: cleanup
  try { if (fs.existsSync(caiqPath)) ws.procurement_vault.caiq = JSON.parse(fs.readFileSync(caiqPath, 'utf8')); } catch {} // deliberate: cleanup
  return ws;
}

