  // ==========================================================================
  // W779 - air-gapped + sneakernet
  //
  //   GET  /v1/airgap/status            - {enabled, mode, local_teacher_url, ...}
  //   POST /v1/airgap/test              - probe shape; tests assert envelope
  //   POST /v1/sneakernet/pack          - body {artifact_id, artifact_path,
  //                                            dest_path} -> writes a tar
  //   POST /v1/sneakernet/unpack        - body {src_path, dest_dir?} -> verifies
  //
  // All four auth-gate on req.tenant_record. W411 defense-in-depth: every
  // route binds tenant into the args so a future schema change cannot leak
  // across tenants.
  // ==========================================================================
  r.get('/v1/airgap/status', async (req, res) => {
    if (!req.tenant_record) return res.status(401).json({ ok: false, error: 'auth_required' });
    try {
      const mod = await import('./airgap-mode.js');
      return res.status(200).json(mod.airgapStatus());
    } catch (e) {
      return res.status(500).json({
        ok: false,
        error: 'airgap_status_error',
        detail: String((e && e.message) || e),
        version: 'w779-v1',
      });
    }
  });

  r.post('/v1/airgap/test', async (req, res) => {
    if (!req.tenant_record) return res.status(401).json({ ok: false, error: 'auth_required' });
    try {
      const mod = await import('./airgap-mode.js');
      const body = req.body || {};
      // actuallyProbe defaults to false - the route surface intentionally
      // returns shape-only by default so probing does not depend on the
      // network. Operators can opt-in via {actually_probe:true}.
      const envelope = await mod.testNetworkLeak({
        actuallyProbe: body.actually_probe === true,
        probeUrls: Array.isArray(body.probe_urls) ? body.probe_urls : undefined,
      });
      return res.status(200).json(envelope);
    } catch (e) {
      return res.status(500).json({
        ok: false,
        error: 'airgap_test_error',
        detail: String((e && e.message) || e),
        version: 'w779-v1',
      });
    }
  });

  // W869 T4 — /v1/bundle/airgap is intentionally a discoverability stub. The
  // actual builder (src/airgap-bundle.js) writes a multi-hundred-MB tarball
  // and reads the entire kolm source tree from disk; streaming that through
  // an HTTP response would balloon memory, leak the server's checkout layout,
  // and lock the route into one host's filesystem. The CLI is the supported
  // path — `kolm bundle airgap --out <path>`. The route still exists so
  // surface discovery + docs can link to it and so a future CDN-backed
  // implementation has a stable URL.
  r.post('/v1/bundle/airgap', async (req, res) => {
    if (!req.tenant_record) return res.status(401).json({ ok: false, error: 'auth_required' });
    return res.status(501).json({
      ok: false,
      error: 'bundle_airgap_requires_cli',
      hint: 'air-gap bundle builds are CLI-only — run `kolm bundle airgap --out <path.tar.gz>` on the host with the kolm checkout. See docs/self-hosted-deploy-complete.md §10 for full flow.',
      cli_command: 'kolm bundle airgap --out /tmp/kolm-airgap.tar.gz [--with-node-modules] [--with-wheels] [--with-models]',
      docs_url: '/docs/self-hosted-deploy-complete',
      version: 'w869-v1',
    });
  });

